function turtleImpact(src,crit,strong){let vx=Number(src&&src.vx)||0,vy=Number(src&&src.vy)||0,len=Math.sqrt(vx*vx+vy*vy)||1;let hitFrames=strong?16:(crit?14:9);if(turtle.hit<=0)turtle.hitMax=hitFrames;else turtle.hitMax=Math.max(turtle.hitMax||0,hitFrames);turtle.hit=Math.max(turtle.hit,hitFrames);turtle.hitX=vx/len;turtle.hitY=vy/len;turtle.hitCrit=!!crit;let count=strong?12:(crit?10:5),ix=src&&Number.isFinite(src.x)?src.x:turtle.x,iy=src&&Number.isFinite(src.y)?src.y:turtle.y;for(let i=0;i<count;i++){let a=Math.atan2(vy,vx)+Math.PI+(Math.random()-.5)*1.9,sp=(strong?2.4:1.4)+Math.random()*(crit?4.2:2.8);turtleChips.push({x:ix,y:iy,vx:Math.cos(a)*sp+vx*.12,vy:Math.sin(a)*sp+vy*.12-1.1,life:18+Math.random()*18,max:36,size:2+Math.random()*(crit?4:2.5),rot:Math.random()*6,spin:(Math.random()-.5)*.35,c:['#b87333','#d9a441','#4f6b2a','#20201d'][i%4]})}}
